import streamlit as stfrom streamlit_gsheets import GSheetsConnectionimport pandas as pdfrom datetime import datetime, timedeltaimport urllib.parseimport plotly.express as pximport warnings# Gereksiz uyarıları gizlewarnings.filterwarnings("ignore")# --- 1. SAYFA AYARLARI ---st.set_page_config(    page_title="Bostanlı Çözüm VIP",     layout="wide",     page_icon="🏫",    initial_sidebar_state="collapsed" )# Arayüz temizleme ve Tasarım (CSS)st.markdown("""    <style>    #MainMenu {visibility: hidden;}    footer {visibility: hidden;}    header {visibility: hidden;}    .stDeployButton {display:none;}    .stTabs [data-baseweb="tab-list"] {        gap: 10px;        background-color: #f0f2f6;        padding: 10px;        border-radius: 10px;    }    .stTabs [data-baseweb="tab"] {        height: 50px;        white-space: pre-wrap;        background-color: #ffffff;        border-radius: 5px;        padding: 10px 20px;        font-weight: bold;    }    </style>    """, unsafe_allow_html=True)# --- 2. ÇİFTLİ ŞİFRE SİSTEMİ ---def check_password():    if "user_role" not in st.session_state:        st.title("🔐 Kurumsal Yönetim Paneli")        pwd = st.text_input("Giriş Şifresi", type="password")        if st.button("Sisteme Giriş Yap"):            if pwd == "cozum35":                st.session_state["user_role"] = "admin"                st.rerun()            elif pwd == "personel35":                st.session_state["user_role"] = "staff"                st.rerun()            else:                st.error("❌ Hatalı şifre. Lütfen tekrar deneyin.")        return False    return Trueif check_password():    conn = st.connection("gsheets", type=GSheetsConnection)    role = st.session_state["user_role"]    def wa_link(tel, mesaj):        tel_str = str(tel).replace(" ", "").replace("-", "").replace("(", "").replace(")", "")        if tel_str.startswith("0"): tel_str = "90" + tel_str[1:]        elif not tel_str.startswith("90"): tel_str = "90" + tel_str        return f"https://wa.me/{tel_str}?text={urllib.parse.quote(mesaj)}"    # --- 3. ÜST BAŞLIK VE ÇIKIŞ ---    c_title, c_exit = st.columns([4, 1])    with c_title:        st.title(f"🏫 Bostanlı Çözüm VIP ({'Kurucu' if role == 'admin' else 'Personel'} Paneli)")    with c_exit:        if st.button("🚪 Güvenli Çıkış"):            del st.session_state["user_role"]            st.rerun()    # --- 4. YETKİYE GÖRE SEKMELER ---    if role == "admin":        tabs = st.tabs(["📞 Veli Görüşmeleri", "💰 Kasa İşlemleri", "🚨 Günlük Olaylar", "📊 Kurucu Raporu", "📈 Gelişmiş Analiz"])    else:        tabs = st.tabs(["📞 Veli Görüşmeleri", "💰 Kasa İşlemleri", "🚨 Günlük Olaylar", "📝 Kurucuya Rapor Gönder"])    # --- 📞 TAB 1: VELİ GÖRÜŞMELERİ ---    with tabs[0]:        st.header("📞 Veli Görüşme Kayıt & Düzenleme")        try:            df_v = conn.read(worksheet="gorusmeler", ttl=0)        except:            df_v = pd.DataFrame(columns=["Tarih", "Veli Ad Soyad", "Öğrenci Ad Soyad", "Telefon", "Konu", "Durum", "Notlar", "Görüşmeyi Yapan"])                with st.expander("➕ Yeni Görüşme Ekle"):            with st.form("v_form", clear_on_submit=True):                v_tarih = st.date_input("Görüşme Tarihi", datetime.now(), format="DD/MM/YYYY")                c1, c2 = st.columns(2)                v_ad = c1.text_input("Veli Ad Soyad *")                o_ad = c1.text_input("Öğrenci Ad Soyad *")                v_tel = c2.text_input("Telefon Numarası *")                v_konu = c2.selectbox("Konu *", ["Seçiniz...", "Yeni Kayıt", "YKS Hazırlık", "LGS Hazırlık", "Ara Sınıf Hazırlık", "Online Kamp", "Yüz Yüze Kamp", "Kayıt Silme", "Diğer"])                v_yapan = st.text_input("Görüşmeyi Yapan Personel *")                v_durum = st.selectbox("Durum *", ["Seçiniz...", "Beklemede", "Olumlu", "Olumsuz", "Kayıt Tamamlandı", "İptal"])                v_not = st.text_area("Görüşme Notları *")                                if st.form_submit_button("Kaydı Tamamla"):                    if v_ad and o_ad and v_tel and v_konu != "Seçiniz...":                        new = pd.DataFrame([{"Tarih": v_tarih.strftime("%Y-%m-%d"), "Veli Ad Soyad": v_ad, "Öğrenci Ad Soyad": o_ad, "Telefon": v_tel, "Konu": v_konu, "Durum": v_durum, "Notlar": v_not, "Görüşmeyi Yapan": v_yapan}])                        conn.update(worksheet="gorusmeler", data=pd.concat([df_v, new], ignore_index=True))                        st.success(f"✅ {o_ad} için kayıt tamamlandı.")                    else:                        st.error("⚠️ Eksik alanları doldurun!")        st.subheader("🔍 Kayıtları Düzenle (Excel Modu)")        v_edited = st.data_editor(df_v, num_rows="dynamic", use_container_width=True, key="v_editor")        if st.button("📞 Görüşme Listesini Güncelle"):            conn.update(worksheet="gorusmeler", data=v_edited)            st.success("Görüşme listesi başarıyla güncellendi!")    # --- 💰 TAB 2: KASA İŞLEMLERİ ---    with tabs[1]:        st.header("💰 Kasa Giriş / Çıkış & Düzenleme")        try:            df_k = conn.read(worksheet="kasa", ttl=0)        except:            df_k = pd.DataFrame(columns=["Tarih", "Tip", "Kategori", "Miktar", "Detay"])        with st.expander("➕ Yeni Kasa İşlemi"):            k_tarih = st.date_input("İşlem Tarihi", datetime.now(), format="DD/MM/YYYY")            k_tip = st.radio("İşlem Türü:", ["Gelir (Tahsilat)", "Gider (Ödeme)"], horizontal=True)            k_kalemler = ["Aidat Ödemesi", "Özel Ders Ödemesi", "Yayın Paketi", "Kira", "Maaş", "Market", "Fatura", "Diğer"]            k_kat = st.selectbox("Kategori Seçin *", k_kalemler)            k_tutar = st.number_input("Tutar (TL) *", min_value=0.0)            k_detay = st.text_input("Açıklama *")            if st.button("İşlemi Kaydet"):                new_k = pd.DataFrame([{"Tarih": k_tarih.strftime("%Y-%m-%d"), "Tip": k_tip, "Kategori": k_kat, "Miktar": k_tutar, "Detay": k_detay}])                conn.update(worksheet="kasa", data=pd.concat([df_k, new_k], ignore_index=True))                st.success("Kasa güncellendi!")        st.subheader("🔍 Kasa Hareketlerini Düzenle")        k_edited = st.data_editor(df_k, num_rows="dynamic", use_container_width=True, key="k_editor")        if st.button("💰 Kasa Verilerini Güncelle"):            conn.update(worksheet="kasa", data=k_edited)            st.success("Kasa verileri güncellendi!")    # --- 🚨 TAB 3: GÜNLÜK OLAYLAR ---    with tabs[2]:        st.header("🚨 Günlük Olay Kaydı")        try:            df_o = conn.read(worksheet="olaylar", ttl=0)        except:            df_o = pd.DataFrame(columns=["Tarih", "Olay Tipi", "Detay"])                with st.form("o_form"):            o_t = st.date_input("Tarih", datetime.now())            o_tip = st.selectbox("Tip", ["Acil", "Ziyaretçi", "Şikayet", "Diğer"])            o_det = st.text_area("Detay")            if st.form_submit_button("Olayı Kaydet"):                new_o = pd.DataFrame([{"Tarih": o_t.strftime("%Y-%m-%d"), "Olay Tipi": o_tip, "Detay": o_det}])                conn.update(worksheet="olaylar", data=pd.concat([df_o, new_o], ignore_index=True))                st.success("Olay kaydedildi.")    # --- 📊 RAPORLAMA FONKSİYONU ---    def generate_detailed_report(target_date_str):        try:            dv = conn.read(worksheet="gorusmeler", ttl=0)            dk = conn.read(worksheet="kasa", ttl=0)            do = conn.read(worksheet="olaylar", ttl=0)            dv_b = dv[dv['Tarih'].astype(str).str.contains(target_date_str, na=False)]            dk_b = dk[dk['Tarih'].astype(str).str.contains(target_date_str, na=False)]            do_b = do[do['Tarih'].astype(str).str.contains(target_date_str, na=False)]            dk_b['Miktar'] = pd.to_numeric(dk_b['Miktar'], errors='coerce').fillna(0)            gelir_df = dk_b[dk_b['Tip'] == 'Gelir (Tahsilat)']            gider_df = dk_b[dk_b['Tip'] == 'Gider (Ödeme)']            t_gelir = gelir_df['Miktar'].sum()            t_gider = gider_df['Miktar'].sum()            msg = f"*🏫 BOSTANLI ÇÖZÜM VIP RAPOR ({datetime.strptime(target_date_str, '%Y-%m-%d').strftime('%d.%m.%Y')})*\n\n"            msg += f"💰 Gelir: {t_gelir:,.0f} TL | 💸 Gider: {t_gider:,.0f} TL\n📈 Net: {t_gelir - t_gider:,.0f} TL\n\n"            if not dv_b.empty:                msg += "*📞 GÖRÜŞMELER:*\n"                for _, r in dv_b.iterrows(): msg += f"- {r['Öğrenci Ad Soyad']} ({r['Konu']})\n"                        return {"msg": msg, "data": {"dv_b": dv_b, "gelir_df": gelir_df, "gider_df": gider_df, "do_b": do_b, "t_gelir": t_gelir, "t_gider": t_gider}}        except: return None    # --- KURUCU RAPORU & ANALİZ ---    if role == "admin":        with tabs[3]:            st.header("📊 Günlük Detaylı Rapor")            t_sec = st.date_input("Rapor Tarihi", datetime.now())            report = generate_detailed_report(t_sec.strftime("%Y-%m-%d"))            if report:                st.metric("Net Durum", f"{report['data']['t_gelir'] - report['data']['t_gider']:,.0f} TL")                st.dataframe(report["data"]["dv_b"], use_container_width=True)                st.markdown(f'[(📲 WhatsApp Gönder)]({wa_link("905492551912", report["msg"])})')        with tabs[4]:            st.header("📈 Gelişmiş Performans Analizi")            df_g = conn.read(worksheet="gorusmeler", ttl=0)            if not df_g.empty:                col1, col2 = st.columns(2)                with col1:                    st.plotly_chart(px.pie(df_g, names='Durum', title="Görüşme Başarı Oranı", hole=0.4), use_container_width=True)                with col2:                    if 'Görüşmeyi Yapan' in df_g.columns:                        perf = df_g['Görüşmeyi Yapan'].value_counts().reset_index()                        perf.columns = ['Personel', 'Sayı']                        st.plotly_chart(px.bar(perf, x='Personel', y='Sayı', title="Personel Performansı"), use_container_width=True)    # --- PERSONEL RAPOR GÖNDERME ---    if role == "staff":        with tabs[3]:            st.header("📝 Raporu Tufan Bey'e İlet")            report = generate_detailed_report(datetime.now().strftime("%Y-%m-%d"))            if report:                st.write(f"Tahsilat: **{report['data']['t_gelir']:,.0f} TL**")                st.markdown(f'### [(📲 RAPORU GÖNDER)]({wa_link("905492551912", report["msg"])})')